// Abstract Products (defined by contract/duck typing in JS)
class Chair {
  sitOn() { throw new Error('sitOn() must be implemented'); }
}

class Sofa {
  sitOn() { throw new Error('sitOn() must be implemented'); }
}

// Concrete Products — Modern
class ModernChair extends Chair {
  sitOn() { console.log('Sitting on a sleek modern chair.'); }
}

class ModernSofa extends Sofa {
  sitOn() { console.log('Sitting on a comfortable modern sofa.'); }
}

// Concrete Products — Victorian
class VictorianChair extends Chair {
  sitOn() { console.log('Sitting on an ornate Victorian chair.'); }
}

class VictorianSofa extends Sofa {
  sitOn() { console.log('Sitting on a grand Victorian sofa.'); }
}

// Abstract Factory
class FurnitureFactory {
  createChair() { throw new Error('createChair() must be implemented'); }
  createSofa() { throw new Error('createSofa() must be implemented'); }
}

// Concrete Factories
class ModernFurnitureFactory extends FurnitureFactory {
  createChair() { return new ModernChair(); }
  createSofa() { return new ModernSofa(); }
}

class VictorianFurnitureFactory extends FurnitureFactory {
  createChair() { return new VictorianChair(); }
  createSofa() { return new VictorianSofa(); }
}

// Client — works only with abstract interfaces
function furnishRoom(factory) {
  const chair = factory.createChair();
  const sofa = factory.createSofa();
  chair.sitOn();
  sofa.sitOn();
}

// Usage
furnishRoom(new ModernFurnitureFactory());
// Sitting on a sleek modern chair.
// Sitting on a comfortable modern sofa.

furnishRoom(new VictorianFurnitureFactory());
// Sitting on an ornate Victorian chair.
// Sitting on a grand Victorian sofa.

