from __future__ import annotations
from abc import ABC, abstractmethod


# Abstract Products
class Chair(ABC):
    @abstractmethod
    def sit_on(self) -> None: ...


class Sofa(ABC):
    @abstractmethod
    def sit_on(self) -> None: ...


# Concrete Products — Modern
class ModernChair(Chair):
    def sit_on(self) -> None:
        print('Sitting on a sleek modern chair.')


class ModernSofa(Sofa):
    def sit_on(self) -> None:
        print('Sitting on a comfortable modern sofa.')


# Concrete Products — Victorian
class VictorianChair(Chair):
    def sit_on(self) -> None:
        print('Sitting on an ornate Victorian chair.')


class VictorianSofa(Sofa):
    def sit_on(self) -> None:
        print('Sitting on a grand Victorian sofa.')


# Abstract Factory
class FurnitureFactory(ABC):
    @abstractmethod
    def create_chair(self) -> Chair: ...

    @abstractmethod
    def create_sofa(self) -> Sofa: ...


# Concrete Factories
class ModernFurnitureFactory(FurnitureFactory):
    def create_chair(self) -> Chair:
        return ModernChair()

    def create_sofa(self) -> Sofa:
        return ModernSofa()


class VictorianFurnitureFactory(FurnitureFactory):
    def create_chair(self) -> Chair:
        return VictorianChair()

    def create_sofa(self) -> Sofa:
        return VictorianSofa()


# Client — depends only on abstract interfaces
def furnish_room(factory: FurnitureFactory) -> None:
    chair = factory.create_chair()
    sofa = factory.create_sofa()
    chair.sit_on()
    sofa.sit_on()


# Usage
furnish_room(ModernFurnitureFactory())
# Sitting on a sleek modern chair.
# Sitting on a comfortable modern sofa.

furnish_room(VictorianFurnitureFactory())
# Sitting on an ornate Victorian chair.
# Sitting on a grand Victorian sofa.
